Role management is a critical security concern. Many developers accidentally allow privilege escalation by trusting client-provided role data. Let me show you a dangerous pattern I've seen in production systems and how to fix it.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

app.use(express.json());

// Vulnerable: User can update ANY field including role
app.put('/api/users/:id', async (req, res) => {
  const userId = req.params.id;
  const updates = req.body; // Dangerous: accepts all fields from client

  try {
    // Directly spreading user input into database update
    const result = await db.collection('users').updateOne(
      { _id: userId },
      { $set: updates } // Attacker can set { role: 'admin' }
    );

    res.json({ success: true, message: 'Profile updated' });
  } catch (error) {
    res.status(500).json({ error: 'Update failed' });
  }
});

// Vulnerable: Role check only on frontend
app.get('/api/admin/users', async (req, res) => {
  // No server-side role verification!
  const users = await db.collection('users').find({}).toArray();
  res.json(users);
});
```

**Attack Payload**:
```bash
# Normal user escalates to admin by including role in update request
curl -X PUT http://localhost:3000/api/users/user123 \
  -H "Content-Type: application/json" \
  -H "Authorization: Bearer <user_jwt_token>" \
  -d '{"name": "John Doe", "role": "admin", "permissions": ["read", "write", "delete", "admin"]}'
```

**Why This Is Dangerous**:
- Mass assignment vulnerability allows users to modify protected fields like `role`, `permissions`, `isAdmin`
- No server-side authorization check before performing privileged operations
- Trusts client-side role information embedded in JWT without verification
- Attacker becomes admin and gains full system access

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const Joi = require('joi');
const app = express();

app.use(express.json());

// Define allowed fields for user self-update (whitelist approach)
const userUpdateSchema = Joi.object({
  name: Joi.string().min(1).max(100),
  email: Joi.string().email(),
  bio: Joi.string().max(500),
  avatar: Joi.string().uri()
  // Note: role, permissions, isAdmin are NOT included
}).min(1);

// Middleware: Verify JWT and load fresh user role from database
const authenticate = async (req, res, next) => {
  try {
    const token = req.headers.authorization?.split(' ')[1];
    if (!token) return res.status(401).json({ error: 'No token provided' });

    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // CRITICAL: Always fetch current role from database, never trust token
    const user = await db.collection('users').findOne({ _id: decoded.userId });
    if (!user) return res.status(401).json({ error: 'User not found' });

    req.user = user; // Fresh user data with current role
    next();
  } catch (error) {
    res.status(401).json({ error: 'Invalid token' });
  }
};

// Middleware: Role-based access control
const requireRole = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user || !allowedRoles.includes(req.user.role)) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
};

// Secure: Whitelist allowed fields, verify ownership
app.put('/api/users/:id', authenticate, async (req, res) => {
  const userId = req.params.id;

  // Users can only update their own profile (unless admin)
  if (req.user._id !== userId && req.user.role !== 'admin') {
    return res.status(403).json({ error: 'Cannot update other users' });
  }

  // Validate and whitelist input fields
  const { error, value } = userUpdateSchema.validate(req.body);
  if (error) {
    return res.status(400).json({ error: error.details[0].message });
  }

  // Only whitelisted fields are updated
  const result = await db.collection('users').updateOne(
    { _id: userId },
    { $set: value }
  );

  res.json({ success: true, message: 'Profile updated' });
});

// Secure: Server-side role verification for admin endpoints
app.get('/api/admin/users', authenticate, requireRole('admin'), async (req, res) => {
  const users = await db.collection('users').find({}).toArray();
  res.json(users);
});
```

**Key Security Controls**:
- **Whitelist approach**: Only explicitly allowed fields can be updated using Joi schema validation
- **Fresh role verification**: Always fetch user role from database, never trust JWT claims alone
- **Ownership check**: Users can only modify their own resources unless they're admin
- **Role-based middleware**: Centralized authorization check before accessing protected endpoints

Excellent question! Admin role changes require extra security controls because they're high-risk operations. You need separation of duties, audit logging, and additional verification to prevent both external attacks and insider threats.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const Joi = require('joi');
const crypto = require('crypto');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

// Secure audit logger - writes to separate audit log
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'audit-security.log' }),
    new winston.transports.Console() // Also log to SIEM in production
  ]
});

// Role hierarchy for validation
const ROLE_HIERARCHY = {
  'user': 1,
  'moderator': 2,
  'admin': 3,
  'superadmin': 4
};

const VALID_ROLES = Object.keys(ROLE_HIERARCHY);

// Rate limit for sensitive operations
const adminRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 role changes per 15 minutes
  message: { error: 'Too many role modification attempts' },
  standardHeaders: true,
  legacyHeaders: false
});

// Schema for admin role change request
const roleChangeSchema = Joi.object({
  newRole: Joi.string().valid(...VALID_ROLES).required(),
  reason: Joi.string().min(10).max(500).required(), // Require justification
  confirmAction: Joi.boolean().valid(true).required() // Explicit confirmation
});

// Middleware: Enhanced authentication with session validation
const authenticate = async (req, res, next) => {
  try {
    const token = req.headers.authorization?.split(' ')[1];
    if (!token) {
      auditLogger.warn({ event: 'AUTH_FAILURE', reason: 'No token', ip: req.ip });
      return res.status(401).json({ error: 'Authentication required' });
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // Verify session is still valid (not revoked)
    const session = await db.collection('sessions').findOne({
      userId: decoded.userId,
      tokenHash: crypto.createHash('sha256').update(token).digest('hex'),
      revokedAt: null
    });

    if (!session) {
      auditLogger.warn({ event: 'AUTH_FAILURE', reason: 'Session invalid', userId: decoded.userId });
      return res.status(401).json({ error: 'Session expired or revoked' });
    }

    // Always fetch fresh user data from database
    const user = await db.collection('users').findOne({ _id: decoded.userId });
    if (!user || user.accountLocked) {
      return res.status(401).json({ error: 'Account not available' });
    }

    req.user = user;
    req.sessionId = session._id;
    next();
  } catch (error) {
    auditLogger.error({ event: 'AUTH_ERROR', error: error.message, ip: req.ip });
    res.status(401).json({ error: 'Authentication failed' });
  }
};

// Middleware: Require specific role with hierarchy check
const requireMinRole = (minRole) => {
  return (req, res, next) => {
    const userLevel = ROLE_HIERARCHY[req.user.role] || 0;
    const requiredLevel = ROLE_HIERARCHY[minRole] || 999;

    if (userLevel < requiredLevel) {
      auditLogger.warn({
        event: 'AUTHORIZATION_FAILURE',
        userId: req.user._id,
        userRole: req.user.role,
        requiredRole: minRole,
        endpoint: req.originalUrl,
        ip: req.ip
      });
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
};

// Secure admin endpoint: Change user role
app.put('/api/admin/users/:targetUserId/role',
  authenticate,
  adminRateLimiter,
  requireMinRole('admin'),
  async (req, res) => {
    const { targetUserId } = req.params;
    const adminUser = req.user;

    // Validate request body
    const { error, value } = roleChangeSchema.validate(req.body);
    if (error) {
      return res.status(400).json({ error: error.details[0].message });
    }

    const { newRole, reason } = value;

    try {
      // Fetch target user
      const targetUser = await db.collection('users').findOne({ _id: targetUserId });
      if (!targetUser) {
        return res.status(404).json({ error: 'User not found' });
      }

      // CRITICAL: Admins cannot escalate users above their own level
      const adminLevel = ROLE_HIERARCHY[adminUser.role];
      const targetNewLevel = ROLE_HIERARCHY[newRole];
      const targetCurrentLevel = ROLE_HIERARCHY[targetUser.role];

      if (targetNewLevel >= adminLevel) {
        auditLogger.warn({
          event: 'PRIVILEGE_ESCALATION_ATTEMPT',
          adminId: adminUser._id,
          adminRole: adminUser.role,
          targetUserId: targetUserId,
          attemptedRole: newRole,
          ip: req.ip
        });
        return res.status(403).json({ 
          error: 'Cannot assign role equal to or higher than your own' 
        });
      }

      // CRITICAL: Cannot modify users at or above your level
      if (targetCurrentLevel >= adminLevel) {
        auditLogger.warn({
          event: 'UNAUTHORIZED_ROLE_MODIFICATION',
          adminId: adminUser._id,
          targetUserId: targetUserId,
          targetRole: targetUser.role,
          ip: req.ip
        });
        return res.status(403).json({ 
          error: 'Cannot modify users at or above your role level' 
        });
      }

      // Prevent self-modification
      if (adminUser._id === targetUserId) {
        return res.status(403).json({ error: 'Cannot modify your own role' });
      }

      // Create audit record BEFORE making change
      const auditRecord = {
        _id: crypto.randomUUID(),
        event: 'ROLE_CHANGE',
        timestamp: new Date(),
        adminId: adminUser._id,
        adminEmail: adminUser.email,
        adminRole: adminUser.role,
        targetUserId: targetUserId,
        targetEmail: targetUser.email,
        previousRole: targetUser.role,
        newRole: newRole,
        reason: reason,
        sessionId: req.sessionId,
        ipAddress: req.ip,
        userAgent: req.headers['user-agent']
      };

      // Use transaction for atomic operation
      const session = await db.startSession();
      try {
        await session.withTransaction(async () => {
          // Insert audit record first
          await db.collection('audit_logs').insertOne(auditRecord, { session });

          // Update user role
          await db.collection('users').updateOne(
            { _id: targetUserId },
            { 
              $set: { 
                role: newRole,
                roleChangedAt: new Date(),
                roleChangedBy: adminUser._id
              }
            },
            { session }
          );

          // Invalidate all sessions for target user (force re-login)
          await db.collection('sessions').updateMany(
            { userId: targetUserId },
            { $set: { revokedAt: new Date(), revokedReason: 'Role changed' } },
            { session }
          );
        });
      } finally {
        await session.endSession();
      }

      // Log success
      auditLogger.info({
        event: 'ROLE_CHANGE_SUCCESS',
        ...auditRecord
      });

      // Send notification to target user (async, non-blocking)
      notifyUserRoleChange(targetUser.email, targetUser.role, newRole, reason)
        .catch(err => auditLogger.error({ event: 'NOTIFICATION_FAILED', error: err.message }));

      res.json({
        success: true,
        message: `User role updated from ${targetUser.role} to ${newRole}`,
        auditId: auditRecord._id
      });

    } catch (error) {
      auditLogger.error({
        event: 'ROLE_CHANGE_ERROR',
        adminId: adminUser._id,
        targetUserId: targetUserId,
        error: error.message
      });
      res.status(500).json({ error: 'Role update failed' });
    }
  }
);

// Audit log retrieval for compliance (superadmin only)
app.get('/api/admin/audit-logs',
  authenticate,
  requireMinRole('superadmin'),
  async (req, res) => {
    const { startDate, endDate, eventType, userId } = req.query;

    const filter = {};
    if (startDate) filter.timestamp = { $gte: new Date(startDate) };
    if (endDate) filter.timestamp = { ...filter.timestamp, $lte: new Date(endDate) };
    if (eventType) filter.event = eventType;
    if (userId) filter.$or = [{ adminId: userId }, { targetUserId: userId }];

    const logs = await db.collection('audit_logs')
      .find(filter)
      .sort({ timestamp: -1 })
      .limit(1000)
      .toArray();

    res.json(logs);
  }
);

async function notifyUserRoleChange(email, oldRole, newRole, reason) {
  // Implement email/notification service
  console.log(`Notifying ${email}: Role changed from ${oldRole} to ${newRole}`);
}
```

**Defense in Depth Layers**:

1. **Role Hierarchy Enforcement**:
```javascript
// Admins cannot create users more powerful than themselves
if (targetNewLevel >= adminLevel) {
  return res.status(403).json({ error: 'Cannot assign higher role' });
}
```

2. **Session Invalidation on Role Change**:
```javascript
// Force re-authentication after role change
await db.collection('sessions').updateMany(
  { userId: targetUserId },
  { $set: { revokedAt: new Date() } }
);
```

3. **Atomic Transactions with Audit Trail**:
```javascript
// Audit record created atomically with role change
await session.withTransaction(async () => {
  await db.collection('audit_logs').insertOne(auditRecord, { session });
  await db.collection('users').updateOne({ _id: targetUserId }, update, { session });
});
```

**Additional Protections**:
- **Rate limiting**: 10 role changes per 15 minutes prevents brute force
- **Required justification**: `reason` field creates accountability trail
- **Self-modification prevention**: Admins cannot change their own role
- **Notification system**: Users are informed of role changes
- **Immutable audit logs**: Stored separately for compliance and forensics
- **Session token hashing**: Prevents token theft from audit logs
- **IP and User-Agent logging**: Helps identify compromised accounts

Your code likely has a critical privilege escalation vulnerability. This is one of the most dangerous flaws - it was exploited in CVE-2023-2825 (GitLab) where any authenticated user could elevate to admin, compromising 30,000+ instances.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.sql.*;
import com.google.gson.Gson;

public class UserProfileServlet extends HttpServlet {

    private static final String DB_URL = "jdbc:postgresql://localhost/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @Override
    protected void doPut(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        HttpSession session = request.getSession(false);
        if (session == null || session.getAttribute("userId") == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
            return;
        }

        // VULNERABLE: Accepts role from user input without authorization check
        Gson gson = new Gson();
        ProfileUpdateRequest updateRequest = gson.fromJson(
            request.getReader(), ProfileUpdateRequest.class);

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // DANGEROUS: User can set ANY role including 'ADMIN'
            String sql = "UPDATE users SET name = ?, email = ?, role = ? WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, updateRequest.getName());
            stmt.setString(2, updateRequest.getEmail());
            stmt.setString(3, updateRequest.getRole());  // VULNERABILITY HERE
            stmt.setInt(4, (Integer) session.getAttribute("userId"));
            stmt.executeUpdate();

            response.setStatus(HttpServletResponse.SC_OK);
        } catch (SQLException e) {
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        }
    }
}

class ProfileUpdateRequest {
    private String name;
    private String email;
    private String role;  // User-controlled field!

    public String getName() { return name; }
    public String getEmail() { return email; }
    public String getRole() { return role; }
}
```

**Attack Payload**:
```json
{
  "name": "John Doe",
  "email": "john@example.com",
  "role": "ADMIN"
}
```

**Why This Is Dangerous**:
- Any authenticated user can set their role to ADMIN by including it in the request
- Server blindly trusts user-supplied role value without authorization check
- No validation that the requesting user has permission to modify roles
- Mass assignment vulnerability allows updating sensitive fields

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.util.*;
import com.google.gson.Gson;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureUserProfileServlet extends HttpServlet {

    private static final Logger logger = LoggerFactory.getLogger(SecureUserProfileServlet.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    // SECURITY: Whitelist of fields users can modify themselves
    private static final Set<String> SELF_UPDATABLE_FIELDS = 
        Set.of("name", "email", "phone", "timezone");

    @Override
    protected void doPut(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        HttpSession session = request.getSession(false);
        if (session == null || session.getAttribute("userId") == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
            return;
        }

        Integer userId = (Integer) session.getAttribute("userId");
        String userRole = (String) session.getAttribute("userRole");

        Gson gson = new Gson();
        SafeProfileUpdateRequest updateRequest = gson.fromJson(
            request.getReader(), SafeProfileUpdateRequest.class);

        // SECURITY: Only allow whitelisted fields - role is NOT included
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "UPDATE users SET name = ?, email = ? WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, sanitize(updateRequest.getName()));
            stmt.setString(2, sanitize(updateRequest.getEmail()));
            stmt.setInt(3, userId);

            int rowsAffected = stmt.executeUpdate();

            // SECURITY: Audit logging
            logger.info("Profile update: userId={}, fields=[name,email], success={}",
                userId, rowsAffected > 0);

            response.setStatus(HttpServletResponse.SC_OK);
        } catch (SQLException e) {
            logger.error("Database error during profile update for userId={}", userId, e);
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        }
    }

    private String sanitize(String input) {
        if (input == null) return null;
        return input.trim().replaceAll("[<>\"']", "");
    }
}

// SECURITY: DTO without sensitive fields
class SafeProfileUpdateRequest {
    private String name;
    private String email;
    // NOTE: 'role' field intentionally omitted - users cannot self-modify

    public String getName() { return name; }
    public String getEmail() { return email; }
}
```

**Key Security Controls**:
- **Whitelist approach**: DTO explicitly excludes sensitive fields like 'role' - even if attacker sends role in JSON, it's ignored
- **Server-side role from session**: User's role comes from authenticated session, never from request body
- **Audit logging**: All profile changes are logged with user context for forensic analysis
- **Separate endpoints**: Role changes require dedicated admin endpoint with proper authorization

For admin role management, you need a completely separate endpoint with multiple layers of authorization checks. Here's a production-ready implementation with defense in depth:

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.sql.*;
import java.util.*;
import java.time.Instant;
import com.google.gson.Gson;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@WebServlet("/admin/users/role")
public class AdminRoleManagementServlet extends HttpServlet {

    private static final Logger logger = LoggerFactory.getLogger(AdminRoleManagementServlet.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private static final String DB_URL = "jdbc:postgresql://localhost/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    // SECURITY: Valid roles whitelist - prevents injection of arbitrary roles
    private static final Set<String> VALID_ROLES = Set.of("USER", "MODERATOR", "ADMIN", "SUPER_ADMIN");

    // SECURITY: Role hierarchy - defines who can assign what
    private static final Map<String, Set<String>> ROLE_ASSIGNMENT_PERMISSIONS = Map.of(
        "ADMIN", Set.of("USER", "MODERATOR"),
        "SUPER_ADMIN", Set.of("USER", "MODERATOR", "ADMIN")
    );

    @Override
    protected void doPut(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String requestId = UUID.randomUUID().toString();
        String clientIp = getClientIp(request);

        // LAYER 1: Authentication check
        HttpSession session = request.getSession(false);
        if (session == null || session.getAttribute("userId") == null) {
            auditLogger.warn("requestId={} action=ROLE_CHANGE status=DENIED reason=NOT_AUTHENTICATED ip={}",
                requestId, clientIp);
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Authentication required");
            return;
        }

        Integer adminUserId = (Integer) session.getAttribute("userId");
        String adminRole = (String) session.getAttribute("userRole");

        // LAYER 2: Role-based access control - only ADMIN and SUPER_ADMIN can modify roles
        if (!ROLE_ASSIGNMENT_PERMISSIONS.containsKey(adminRole)) {
            auditLogger.warn("requestId={} action=ROLE_CHANGE status=DENIED adminId={} adminRole={} reason=INSUFFICIENT_PRIVILEGES ip={}",
                requestId, adminUserId, adminRole, clientIp);
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Insufficient privileges");
            return;
        }

        Gson gson = new Gson();
        RoleChangeRequest roleRequest;
        try {
            roleRequest = gson.fromJson(request.getReader(), RoleChangeRequest.class);
        } catch (Exception e) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid request format");
            return;
        }

        // LAYER 3: Input validation
        if (roleRequest.getTargetUserId() == null || roleRequest.getNewRole() == null) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing required fields");
            return;
        }

        // LAYER 4: Role whitelist validation
        String newRole = roleRequest.getNewRole().toUpperCase().trim();
        if (!VALID_ROLES.contains(newRole)) {
            auditLogger.warn("requestId={} action=ROLE_CHANGE status=DENIED adminId={} reason=INVALID_ROLE attemptedRole={} ip={}",
                requestId, adminUserId, newRole, clientIp);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid role specified");
            return;
        }

        // LAYER 5: Role hierarchy enforcement - can this admin assign this role?
        Set<String> assignableRoles = ROLE_ASSIGNMENT_PERMISSIONS.get(adminRole);
        if (!assignableRoles.contains(newRole)) {
            auditLogger.warn("requestId={} action=ROLE_CHANGE status=DENIED adminId={} adminRole={} targetRole={} reason=ROLE_HIERARCHY_VIOLATION ip={}",
                requestId, adminUserId, adminRole, newRole, clientIp);
            response.sendError(HttpServletResponse.SC_FORBIDDEN, 
                "You cannot assign the role: " + newRole);
            return;
        }

        // LAYER 6: Self-escalation prevention
        if (roleRequest.getTargetUserId().equals(adminUserId)) {
            auditLogger.warn("requestId={} action=ROLE_CHANGE status=DENIED adminId={} reason=SELF_ESCALATION_ATTEMPT ip={}",
                requestId, adminUserId, clientIp);
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Cannot modify your own role");
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            conn.setAutoCommit(false);

            // LAYER 7: Verify target user exists and get current role
            String currentRole = getCurrentUserRole(conn, roleRequest.getTargetUserId());
            if (currentRole == null) {
                response.sendError(HttpServletResponse.SC_NOT_FOUND, "Target user not found");
                return;
            }

            // LAYER 8: Cannot demote users with higher privilege than yourself
            if (isHigherPrivilege(currentRole, adminRole)) {
                auditLogger.warn("requestId={} action=ROLE_CHANGE status=DENIED adminId={} targetId={} reason=TARGET_HIGHER_PRIVILEGE ip={}",
                    requestId, adminUserId, roleRequest.getTargetUserId(), clientIp);
                response.sendError(HttpServletResponse.SC_FORBIDDEN, 
                    "Cannot modify users with higher privileges");
                return;
            }

            // SECURITY: Update role with audit trail
            updateUserRole(conn, roleRequest.getTargetUserId(), newRole);

            // SECURITY: Record in audit table (immutable log)
            recordRoleChangeAudit(conn, requestId, adminUserId, roleRequest.getTargetUserId(), 
                currentRole, newRole, clientIp);

            conn.commit();

            auditLogger.info("requestId={} action=ROLE_CHANGE status=SUCCESS adminId={} targetId={} previousRole={} newRole={} ip={}",
                requestId, adminUserId, roleRequest.getTargetUserId(), currentRole, newRole, clientIp);

            response.setStatus(HttpServletResponse.SC_OK);
            response.getWriter().write("{\"success\": true, \"requestId\": \"" + requestId + "\"}");

        } catch (SQLException e) {
            logger.error("Database error during role change: requestId={}", requestId, e);
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        }
    }

    private String getCurrentUserRole(Connection conn, Integer userId) throws SQLException {
        String sql = "SELECT role FROM users WHERE id = ? AND deleted_at IS NULL";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setInt(1, userId);
            ResultSet rs = stmt.executeQuery();
            return rs.next() ? rs.getString("role") : null;
