    }

    private void updateUserRole(Connection conn, Integer userId, String newRole) throws SQLException {
        String sql = "UPDATE users SET role = ?, role_updated_at = NOW() WHERE id = ?";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, newRole);
            stmt.setInt(2, userId);
            stmt.executeUpdate();
        }
    }

    private void recordRoleChangeAudit(Connection conn, String requestId, Integer adminId, 
            Integer targetId, String oldRole, String newRole, String clientIp) throws SQLException {
        String sql = "INSERT INTO role_change_audit (request_id, admin_user_id, target_user_id, " +
                     "previous_role, new_role, client_ip, created_at) VALUES (?, ?, ?, ?, ?, ?, NOW())";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, requestId);
            stmt.setInt(2, adminId);
            stmt.setInt(3, targetId);
            stmt.setString(4, oldRole);
            stmt.setString(5, newRole);
            stmt.setString(6, clientIp);
            stmt.executeUpdate();
        }
    }

    private boolean isHigherPrivilege(String role1, String role2) {
        Map<String, Integer> hierarchy = Map.of(
            "USER", 1, "MODERATOR", 2, "ADMIN", 3, "SUPER_ADMIN", 4
        );
        return hierarchy.getOrDefault(role1, 0) > hierarchy.getOrDefault(role2, 0);
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
