Role-based access control (RBAC) is critical but frequently implemented with dangerous flaws. A common mistake is trusting client-provided role information or failing to validate authorization on the server side.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"net/http"
	"strconv"
)

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Role     string `json:"role"`
}

type UpdateRoleRequest struct {
	UserID  int    `json:"user_id"`
	NewRole string `json:"new_role"`
}

// VULNERABLE: No authorization check on who can change roles
func updateUserRole(w http.ResponseWriter, r *http.Request) {
	var req UpdateRoleRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// VULNERABLE: Any authenticated user can set any role
	// No check if the requester has permission to change roles
	_, err := db.Exec("UPDATE users SET role = $1 WHERE id = $2", req.NewRole, req.UserID)
	if err != nil {
		http.Error(w, "Database error", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "role updated"})
}

// VULNERABLE: Role checked from request header instead of server-side
func adminPanel(w http.ResponseWriter, r *http.Request) {
	role := r.Header.Get("X-User-Role")
	if role != "admin" {
		http.Error(w, "Forbidden", http.StatusForbidden)
		return
	}
	// Admin functionality
	w.Write([]byte("Welcome to admin panel"))
