    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    // DANGEROUS: Role checked from session without verification
    public function updateUserRole() {
        session_start();

        // Vulnerable: trusts session role without database verification
        if ($_SESSION['role'] !== 'admin') {
            header('Location: /unauthorized.php');
            exit;
        }

        $userId = $_POST['user_id'];
        $newRole = $_POST['role']; // User-controlled input!

