        session_start();
        $userId = $_SESSION['user_id'];

        // Mass assignment vulnerability - accepts any field from POST
        $fields = [];
        $values = [];
        foreach ($_POST as $key => $value) {
            $fields[] = "$key = ?";
            $values[] = $value;
        }
        $values[] = $userId;

        $sql = "UPDATE users SET " . implode(', ', $fields) . " WHERE id = ?";
