**SECURE VERSION**:

```php
<?php
class SecureAdminController {
    private $pdo;
    private const VALID_ROLES = ['user', 'moderator', 'admin'];
    private const ROLE_HIERARCHY = [
        'user' => 0,
        'moderator' => 1,
        'admin' => 2,
        'superadmin' => 3
    ];

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    // Verify role from database, not session alone
    private function verifyUserRole(int $userId): ?string {
        $stmt = $this->pdo->prepare(
            "SELECT role FROM users WHERE id = ? AND active = 1"
        );
        $stmt->execute([$userId]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);
        return $result ? $result['role'] : null;
    }

    // Check if current user can assign target role
    private function canAssignRole(string $currentRole, string $targetRole): bool {
        $currentLevel = self::ROLE_HIERARCHY[$currentRole] ?? 0;
        $targetLevel = self::ROLE_HIERARCHY[$targetRole] ?? PHP_INT_MAX;

        // Users can only assign roles below their own level
        return $currentLevel > $targetLevel;
    }

    public function updateUserRole(): void {
        session_start();

        // CSRF protection
        if (!$this->validateCsrfToken($_POST['csrf_token'] ?? '')) {
            http_response_code(403);
            echo json_encode(['error' => 'Invalid CSRF token']);
            exit;
        }

        $currentUserId = filter_var($_SESSION['user_id'], FILTER_VALIDATE_INT);
        if (!$currentUserId) {
            http_response_code(401);
            exit;
        }

        // CRITICAL: Verify role from database, not session
        $currentUserRole = $this->verifyUserRole($currentUserId);
        if (!$currentUserRole || $currentUserRole !== 'admin') {
            $this->logSecurityEvent('privilege_escalation_attempt', [
                'user_id' => $currentUserId,
                'session_role' => $_SESSION['role'] ?? 'unknown',
                'db_role' => $currentUserRole,
                'ip' => $_SERVER['REMOTE_ADDR']
            ]);
            http_response_code(403);
            echo json_encode(['error' => 'Insufficient privileges']);
            exit;
        }

        // Validate input
        $targetUserId = filter_var($_POST['user_id'], FILTER_VALIDATE_INT);
        $newRole = $_POST['role'] ?? '';

        if (!$targetUserId || !in_array($newRole, self::VALID_ROLES, true)) {
            http_response_code(400);
            echo json_encode(['error' => 'Invalid parameters']);
            exit;
        }

        // Prevent assigning roles equal to or above own level
        if (!$this->canAssignRole($currentUserRole, $newRole)) {
            $this->logSecurityEvent('role_assignment_denied', [
                'admin_id' => $currentUserId,
                'target_user' => $targetUserId,
                'attempted_role' => $newRole
            ]);
            http_response_code(403);
            echo json_encode(['error' => 'Cannot assign this role level']);
            exit;
        }

        // Perform update with audit trail
        $this->pdo->beginTransaction();
        try {
            // Log the change before making it
            $this->logRoleChange($currentUserId, $targetUserId, $newRole);

            $stmt = $this->pdo->prepare(
                "UPDATE users SET role = ?, updated_at = NOW(), updated_by = ? WHERE id = ?"
            );
            $stmt->execute([$newRole, $currentUserId, $targetUserId]);

            $this->pdo->commit();
            echo json_encode(['success' => true]);
        } catch (Exception $e) {
            $this->pdo->rollBack();
            error_log("Role update failed: " . $e->getMessage());
            http_response_code(500);
            echo json_encode(['error' => 'Update failed']);
        }
    }

    // Safe profile update with whitelist
    public function updateProfile(): void {
        session_start();

        // WHITELIST of allowed fields - role is NOT included
        $allowedFields = ['name', 'email', 'phone', 'timezone'];

        $userId = filter_var($_SESSION['user_id'], FILTER_VALIDATE_INT);
        if (!$userId) {
            http_response_code(401);
            exit;
        }

        $fields = [];
        $values = [];

        foreach ($_POST as $key => $value) {
            // Only process whitelisted fields
            if (in_array($key, $allowedFields, true)) {
                $fields[] = "$key = ?";
                $values[] = htmlspecialchars($value, ENT_QUOTES, 'UTF-8');
            }
        }

        if (empty($fields)) {
            http_response_code(400);
            echo json_encode(['error' => 'No valid fields to update']);
            exit;
        }

        $values[] = $userId;
        $sql = "UPDATE users SET " . implode(', ', $fields) . ", updated_at = NOW() WHERE id = ?";
        $stmt = $this->pdo->prepare($sql);
        $stmt->execute($values);

        echo json_encode(['success' => true]);
    }

    private function validateCsrfToken(string $token): bool {
        return hash_equals($_SESSION['csrf_token'] ?? '', $token);
    }

    private function logSecurityEvent(string $event, array $data): void {
        error_log(json_encode([
            'event' => $event,
            'timestamp' => date('c'),
            'data' => $data
        ]));
    }

    private function logRoleChange(int $adminId, int $targetId, string $newRole): void {
        $stmt = $this->pdo->prepare(
            "INSERT INTO role_audit_log (admin_id, target_user_id, new_role, changed_at, ip_address) 
             VALUES (?, ?, ?, NOW(), ?)"
        );
        $stmt->execute([$adminId, $targetId, $newRole, $_SERVER['REMOTE_ADDR']]);
    }
}
?>
```

**Key Security Controls**:
- **Database role verification**: Always verify roles from the database, never trust session data alone for critical operations
- **Field whitelist**: Explicitly whitelist allowed fields for mass updates, preventing role injection
- **Role hierarchy enforcement**: Users can only assign roles below their own privilege level
- **CSRF protection**: Prevents attackers from tricking admins into making unauthorized role changes
- **Comprehensive audit logging**: All privilege changes are logged with who, what, when, and from where

API protection requires a centralized authorization layer that works consistently across all authentication methods. The key is to never scatter authorization checks throughout your codebase - use middleware that enforces permissions at every entry point.

**PRODUCTION PATTERN**:

```php
<?php
// config/authorization.php - Centralized permission definitions
return [
    'permissions' => [
        'users.view' => ['user', 'moderator', 'admin'],
        'users.create' => ['moderator', 'admin'],
        'users.update' => ['moderator', 'admin'],
        'users.delete' => ['admin'],
        'users.update_role' => ['admin'],
        'settings.view' => ['admin'],
        'settings.modify' => ['admin'],
        'reports.view' => ['moderator', 'admin'],
        'reports.export' => ['admin'],
    ],
    'role_hierarchy' => [
        'user' => 1,
        'moderator' => 2,
        'admin' => 3,
        'superadmin' => 4,
    ],
];
?>
