<?php
// services/AuditLogger.php - Security event logging
namespace App\Services;

class AuditLogger {
    private $pdo;
    private $alertThresholds;

    public function __construct(\PDO $pdo) {
        $this->pdo = $pdo;
        $this->alertThresholds = [
            'privilege_escalation_attempt' => 1,  // Alert on first occurrence
            'auth_failure' => 5,  // Alert after 5 failures
            'role_verification_failed' => 3
        ];
    }

    public function logSecurityEvent(string $eventType, array $data): void {
        $stmt = $this->pdo->prepare(
            "INSERT INTO security_events 
             (event_type, event_data, ip_address, user_agent, created_at)
             VALUES (?, ?, ?, ?, NOW())"
        );
        $stmt->execute([
            $eventType,
            json_encode($data),
            $data['ip'] ?? null,
            $data['user_agent'] ?? null
        ]);

        // Check if we need to trigger alerts
        $this->checkAlertThreshold($eventType, $data);
    }

    public function logAccess(array $data): void {
        $stmt = $this->pdo->prepare(
            "INSERT INTO access_log 
             (user_id, permission, endpoint, method, created_at)
             VALUES (?, ?, ?, ?, NOW())"
        );
        $stmt->execute([
            $data['user_id'],
            $data['permission'],
            $data['endpoint'],
            $data['method']
        ]);
    }

    private function checkAlertThreshold(string $eventType, array $data): void {
        if (!isset($this->alertThresholds[$eventType])) {
            return;
        }

        // Count recent occurrences
        $stmt = $this->pdo->prepare(
            "SELECT COUNT(*) FROM security_events 
             WHERE event_type = ? 
             AND ip_address = ? 
             AND created_at > DATE_SUB(NOW(), INTERVAL 1 HOUR)"
        );
        $stmt->execute([$eventType, $data['ip'] ?? '']);
        $count = $stmt->fetchColumn();

        if ($count >= $this->alertThresholds[$eventType]) {
            $this->triggerSecurityAlert($eventType, $data, $count);
        }
    }

    private function triggerSecurityAlert(string $eventType, array $data, int $count): void {
        // Send to security team via webhook, email, or SIEM
        error_log(sprintf(
            "SECURITY ALERT: %s detected %d times from IP %s",
            $eventType,
            $count,
            $data['ip'] ?? 'unknown'
        ));

        // Could integrate with PagerDuty, Slack, etc.
    }
}
