**Why This Is Dangerous**:
- No verification that the requester has permission to modify roles
- No check that the requester can assign the target role level
- Any authenticated user can escalate their own or others' privileges
- No role hierarchy enforcement (regular user assigning admin roles)
- No audit trail of privilege changes

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.util.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureUserRoleController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureUserRoleController.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/appdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    // Define role hierarchy with numeric levels
    private static final Map<String, Integer> ROLE_HIERARCHY = Map.of(
        "USER", 1,
        "MODERATOR", 2,
        "ADMIN", 3,
        "SUPER_ADMIN", 4
    );

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendError(401, "Authentication required");
            return;
        }

        String requesterId = (String) session.getAttribute("userId");
        String requesterRole = (String) session.getAttribute("userRole");
        String targetUserId = request.getParameter("userId");
        String newRole = request.getParameter("role");

        // SECURITY: Validate role is a known valid role
        if (!ROLE_HIERARCHY.containsKey(newRole)) {
            logger.warn("Invalid role requested: {} by user: {}", newRole, requesterId);
            response.sendError(400, "Invalid role");
            return;
        }

        // SECURITY: Only ADMIN or SUPER_ADMIN can modify roles
        int requesterLevel = ROLE_HIERARCHY.getOrDefault(requesterRole, 0);
        if (requesterLevel < ROLE_HIERARCHY.get("ADMIN")) {
            logger.warn("Privilege escalation attempt by user: {} with role: {}", 
                requesterId, requesterRole);
            response.sendError(403, "Insufficient privileges");
            return;
        }

        // SECURITY: Cannot assign role equal to or higher than your own
        int targetRoleLevel = ROLE_HIERARCHY.get(newRole);
        if (targetRoleLevel >= requesterLevel) {
            logger.warn("User {} attempted to assign role {} (level {}) but only has level {}",
                requesterId, newRole, targetRoleLevel, requesterLevel);
            response.sendError(403, "Cannot assign role at or above your level");
            return;
        }

        // SECURITY: Cannot modify your own role
        if (requesterId.equals(targetUserId)) {
            logger.warn("Self-elevation attempt by user: {}", requesterId);
            response.sendError(403, "Cannot modify your own role");
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // Get current role of target user
            String selectSql = "SELECT role FROM users WHERE id = ?";
            PreparedStatement selectStmt = conn.prepareStatement(selectSql);
            selectStmt.setInt(1, Integer.parseInt(targetUserId));
            ResultSet rs = selectStmt.executeQuery();

            if (!rs.next()) {
                response.sendError(404, "User not found");
                return;
            }

            String currentRole = rs.getString("role");
            int currentRoleLevel = ROLE_HIERARCHY.getOrDefault(currentRole, 0);

            // SECURITY: Cannot modify users at or above your level
            if (currentRoleLevel >= requesterLevel) {
                logger.warn("User {} attempted to modify user {} with higher/equal role",
                    requesterId, targetUserId);
                response.sendError(403, "Cannot modify users at or above your level");
                return;
            }

            // Perform the update with audit logging
            String updateSql = "UPDATE users SET role = ?, role_modified_by = ?, role_modified_at = NOW() WHERE id = ?";
            PreparedStatement updateStmt = conn.prepareStatement(updateSql);
            updateStmt.setString(1, newRole);
            updateStmt.setString(2, requesterId);
            updateStmt.setInt(3, Integer.parseInt(targetUserId));
            updateStmt.executeUpdate();

            // Audit log the change
            logger.info("ROLE_CHANGE: User {} changed role of user {} from {} to {}",
                requesterId, targetUserId, currentRole, newRole);

            response.getWriter().write("{\"success\": true}");
        } catch (SQLException e) {
            logger.error("Database error during role change", e);
            response.sendError(500, "Internal server error");
        }
    }
}
```

**Key Security Controls**:
- **Role hierarchy enforcement**: Users can only assign roles below their own level
- **Self-elevation prevention**: Users cannot modify their own role
- **Target protection**: Cannot modify users at or above your privilege level
- **Whitelist validation**: Only predefined valid roles are accepted
- **Comprehensive audit logging**: All role changes and attempts are logged

Temporary privilege elevation is a powerful pattern used in production systems for incident response and on-call scenarios. It requires careful implementation with automatic expiration and strict auditing.

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.time.*;
import java.util.*;
import java.util.concurrent.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;

public class TemporaryPrivilegeElevationService {
    private static final Logger logger = LoggerFactory.getLogger(TemporaryPrivilegeElevationService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    // Maximum elevation duration by role
    private static final Map<String, Duration> MAX_ELEVATION_DURATION = Map.of(
        "MODERATOR", Duration.ofHours(4),
        "ADMIN", Duration.ofHours(2),
        "SUPER_ADMIN", Duration.ofMinutes(30)
    );

    private static final Map<String, Integer> ROLE_HIERARCHY = Map.of(
        "USER", 1, "MODERATOR", 2, "ADMIN", 3, "SUPER_ADMIN", 4
    );

    private final DataSource dataSource;
    private final NotificationService notificationService;
    private final ScheduledExecutorService scheduler;
    private final RateLimiter elevationRateLimiter;

    public TemporaryPrivilegeElevationService(DataSource dataSource, 
            NotificationService notificationService) {
        this.dataSource = dataSource;
        this.notificationService = notificationService;
        this.scheduler = Executors.newScheduledThreadPool(2);
        this.elevationRateLimiter = RateLimiter.create(5.0); // 5 requests per second max

        // Background task to expire elevated privileges
        scheduler.scheduleAtFixedRate(this::expireElevatedPrivileges, 
            1, 1, TimeUnit.MINUTES);
    }

    public ElevationResult requestTemporaryElevation(
            String requesterId, 
            String targetRole, 
            String justification,
            Duration requestedDuration,
            String incidentId,
            HttpServletRequest request) {

        // Set MDC for structured logging
        MDC.put("requesterId", requesterId);
        MDC.put("targetRole", targetRole);
        MDC.put("incidentId", incidentId);
        MDC.put("clientIp", getClientIp(request));

        try {
            // SECURITY: Rate limiting to prevent abuse
            if (!elevationRateLimiter.tryAcquire(1, TimeUnit.SECONDS)) {
                logger.warn("Rate limit exceeded for elevation request");
                return ElevationResult.rateLimited();
            }

            // SECURITY: Validate target role
            if (!ROLE_HIERARCHY.containsKey(targetRole)) {
                logger.warn("Invalid target role requested: {}", targetRole);
                return ElevationResult.invalidRole();
            }

            // SECURITY: Enforce maximum duration based on role
            Duration maxDuration = MAX_ELEVATION_DURATION.get(targetRole);
            if (maxDuration == null || requestedDuration.compareTo(maxDuration) > 0) {
                logger.warn("Requested duration {} exceeds maximum {} for role {}",
                    requestedDuration, maxDuration, targetRole);
                requestedDuration = maxDuration;
            }

            // SECURITY: Require justification and incident ID for elevated roles
            int targetLevel = ROLE_HIERARCHY.get(targetRole);
            if (targetLevel >= ROLE_HIERARCHY.get("ADMIN")) {
                if (justification == null || justification.length() < 20) {
                    return ElevationResult.justificationRequired();
                }
                if (incidentId == null || incidentId.isBlank()) {
                    return ElevationResult.incidentIdRequired();
                }
            }

            try (Connection conn = dataSource.getConnection()) {
                conn.setAutoCommit(false);

                try {
                    // Get current user info
                    UserInfo currentUser = getUserInfo(conn, requesterId);
                    if (currentUser == null) {
                        return ElevationResult.userNotFound();
                    }

                    // SECURITY: Check if user is eligible for elevation
                    if (!isEligibleForElevation(conn, requesterId, targetRole)) {
                        logger.warn("User {} not eligible for elevation to {}",
                            requesterId, targetRole);
                        return ElevationResult.notEligible();
                    }

                    // SECURITY: Check for active elevation (prevent stacking)
                    if (hasActiveElevation(conn, requesterId)) {
                        logger.warn("User {} already has active elevation", requesterId);
                        return ElevationResult.alreadyElevated();
                    }

                    // SECURITY: Require MFA for admin-level elevation
                    if (targetLevel >= ROLE_HIERARCHY.get("ADMIN")) {
                        if (!verifyMfaForElevation(request)) {
                            return ElevationResult.mfaRequired();
                        }
                    }

                    // Create elevation record
                    Instant expiresAt = Instant.now().plus(requestedDuration);
                    String elevationId = UUID.randomUUID().toString();

                    String insertSql = """
                        INSERT INTO privilege_elevations 
                        (id, user_id, original_role, elevated_role, justification, 
                         incident_id, created_at, expires_at, client_ip, user_agent, status)
                        VALUES (?, ?, ?, ?, ?, ?, NOW(), ?, ?, ?, 'ACTIVE')
                        """;

                    try (PreparedStatement stmt = conn.prepareStatement(insertSql)) {
                        stmt.setString(1, elevationId);
                        stmt.setString(2, requesterId);
                        stmt.setString(3, currentUser.role);
                        stmt.setString(4, targetRole);
                        stmt.setString(5, justification);
                        stmt.setString(6, incidentId);
                        stmt.setTimestamp(7, Timestamp.from(expiresAt));
                        stmt.setString(8, getClientIp(request));
                        stmt.setString(9, request.getHeader("User-Agent"));
                        stmt.executeUpdate();
                    }

                    // Update user's effective role
                    String updateSql = """
                        UPDATE users 
                        SET effective_role = ?, elevation_id = ?, elevation_expires_at = ?
                        WHERE id = ?
                        """;

                    try (PreparedStatement stmt = conn.prepareStatement(updateSql)) {
                        stmt.setString(1, targetRole);
                        stmt.setString(2, elevationId);
                        stmt.setTimestamp(3, Timestamp.from(expiresAt));
                        stmt.setString(4, requesterId);
                        stmt.executeUpdate();
                    }

                    conn.commit();

                    // AUDIT: Log the elevation event
                    auditLogger.info(
                        "PRIVILEGE_ELEVATION: user={} from={} to={} duration={} incident={} justification={}",
                        requesterId, currentUser.role, targetRole, requestedDuration, 
                        incidentId, justification);

                    // NOTIFY: Alert security team for admin elevations
                    if (targetLevel >= ROLE_HIERARCHY.get("ADMIN")) {
                        notificationService.notifySecurityTeam(
                            "Privilege Elevation Alert",
                            String.format("User %s elevated to %s for incident %s. Expires: %s",
                                requesterId, targetRole, incidentId, expiresAt)
                        );
                    }

                    // Schedule automatic revocation
                    scheduler.schedule(
                        () -> revokeElevation(elevationId, "EXPIRED"),
                        requestedDuration.toMillis(),
                        TimeUnit.MILLISECONDS
                    );

                    return ElevationResult.success(elevationId, expiresAt);

                } catch (Exception e) {
                    conn.rollback();
                    throw e;
                }
            }
        } catch (Exception e) {
            logger.error("Error processing elevation request", e);
            return ElevationResult.error();
        } finally {
            MDC.clear();
        }
    }

    public void revokeElevation(String elevationId, String reason) {
        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);

            try {
                // Get elevation details
                String selectSql = """
                    SELECT pe.user_id, pe.original_role, pe.elevated_role, u.effective_role
                    FROM privilege_elevations pe
                    JOIN users u ON pe.user_id = u.id
                    WHERE pe.id = ? AND pe.status = 'ACTIVE'
                    """;

                String userId = null;
                String originalRole = null;
                String elevatedRole = null;

                try (PreparedStatement stmt = conn.prepareStatement(selectSql)) {
                    stmt.setString(1, elevationId);
                    ResultSet rs = stmt.executeQuery();
                    if (rs.next()) {
                        userId = rs.getString("user_id");
                        originalRole = rs.getString("original_role");
                        elevatedRole = rs.getString("elevated_role");
                    } else {
                        logger.warn("Elevation {} not found or already revoked", elevationId);
                        return;
                    }
                }

                // Restore original role
                String updateUserSql = """
                    UPDATE users 
                    SET effective_role = base_role, elevation_id = NULL, elevation_expires_at = NULL
                    WHERE id = ?
                    """;

                try (PreparedStatement stmt = conn.prepareStatement(updateUserSql)) {
                    stmt.setString(1, userId);
                    stmt.executeUpdate();
                }

                // Update elevation record
                String updateElevationSql = """
                    UPDATE privilege_elevations 
                    SET status = 'REVOKED', revoked_at = NOW(), revoke_reason = ?
                    WHERE id = ?
                    """;

                try (PreparedStatement stmt = conn.prepareStatement(updateElevationSql)) {
                    stmt.setString(1, reason);
                    stmt.setString(2, elevationId);
                    stmt.executeUpdate();
                }

                conn.commit();

                auditLogger.info(
                    "PRIVILEGE_REVOCATION: user={} from={} to={} reason={}",
                    userId, elevatedRole, originalRole, reason);

                // Invalidate all active sessions for this user
                invalidateUserSessions(userId);

            } catch (Exception e) {
                conn.rollback();
                throw e;
            }
        } catch (Exception e) {
            logger.error("Error revoking elevation {}", elevationId, e);
        }
    }

    private void expireElevatedPrivileges() {
        try (Connection conn = dataSource.getConnection()) {
            String sql = """
                SELECT id FROM privilege_elevations 
                WHERE status = 'ACTIVE' AND expires_at < NOW()
                """;

            try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                ResultSet rs = stmt.executeQuery();
                while (rs.next()) {
                    revokeElevation(rs.getString("id"), "EXPIRED");
                }
            }
        } catch (Exception e) {
            logger.error("Error in expire elevated privileges task", e);
        }
    }

    private boolean isEligibleForElevation(Connection conn, String userId, String targetRole) 
            throws SQLException {
        // Check if user is in the on-call rotation or has elevation permission
        String sql = """
            SELECT 1 FROM user_elevation_permissions 
            WHERE user_id = ? AND target_role = ? AND is_active = true
            AND (valid_until IS NULL OR valid_until > NOW())
            """;

        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, userId);
            stmt.setString(2, targetRole);
            return stmt.executeQuery().next();
        }
    }

    private boolean hasActiveElevation(Connection conn, String userId) throws SQLException {
        String sql = """
            SELECT 1 FROM privilege_elevations 
            WHERE user_id = ? AND status = 'ACTIVE' AND expires_at > NOW()
            """;

        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, userId);
            return stmt.executeQuery().next();
        }
    }

    private boolean verifyMfaForElevation(HttpServletRequest request) {
        String mfaToken = request.getHeader("X-MFA-Token");
        // Implement MFA verification logic
        return mfaToken != null && validateMfaToken(mfaToken);
    }

    private String getClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        return xff != null ? xff.split(",")[0].trim() : request.getRemoteAddr();
    }

    private void invalidateUserSessions(String userId) {
        // Implementation to invalidate all sessions for security
    }

    private boolean validateMfaToken(String token) {
        // MFA validation implementation
        return true;
    }

    private UserInfo getUserInfo(Connection conn, String userId) throws SQLException {
        String sql = "SELECT id, base_role, effective_role FROM users WHERE id = ?";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, userId);
            ResultSet rs = stmt.executeQuery();
            if (rs.next()) {
                return new UserInfo(rs.getString("id"), rs.getString("base_role"));
            }
        }
        return null;
    }

    private static class UserInfo {
        final String id;
        final String role;
        UserInfo(String id, String role) { this.id = id; this.role = role; }
    }
}
