Role-based access control (RBAC) is critical for preventing vertical privilege escalation attacks. A common vulnerability is trusting user-supplied role data or failing to verify the requester has permission to assign roles.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"net/http"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

type UpdateRoleRequest struct {
	UserID  int    `json:"user_id"`
	NewRole string `json:"new_role"`
}

var db *sql.DB

// VULNERABLE: No authorization check on who can change roles
func updateUserRole(w http.ResponseWriter, r *http.Request) {
	var req UpdateRoleRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// VULNERABLE: Directly updates role without checking requester's permissions
	_, err := db.Exec(
		"UPDATE users SET role = $1 WHERE id = $2",
		req.NewRole, req.UserID,
	)
	if err != nil {
		http.Error(w, "Database error", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "role updated"})
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/api/users/role", updateUserRole).Methods("PUT")
	http.ListenAndServe(":8080", r)
}
```

**Attack Payload**:
```bash
# Regular user promotes themselves to admin
curl -X PUT http://api.example.com/api/users/role \
  -H "Authorization: Bearer user_token_12345" \
  -H "Content-Type: application/json" \
  -d '{"user_id": 12345, "new_role": "admin"}'
```

**Why This Is Dangerous**:
- No verification that the requester has permission to change roles
- Any authenticated user can promote themselves or others to admin
- No validation of valid role values (could set arbitrary roles)
- No audit trail of who made the change

**SECURE VERSION**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"log"
	"net/http"
	"slices"

	"github.com/gorilla/mux"
	_ "github.com/lib/pq"
)

type Role string

const (
	RoleUser    Role = "user"
	RoleMod     Role = "moderator"
	RoleAdmin   Role = "admin"
	RoleOwner   Role = "owner"
)

// Role hierarchy - higher index = more privileges
var roleHierarchy = []Role{RoleUser, RoleMod, RoleAdmin, RoleOwner}

type UpdateRoleRequest struct {
	UserID  int  `json:"user_id"`
	NewRole Role `json:"new_role"`
}

type User struct {
	ID   int
	Role Role
}

var db *sql.DB

// Helper: Get role level (higher = more privileged)
func getRoleLevel(role Role) int {
	return slices.Index(roleHierarchy, role)
}

// Helper: Check if role is valid
func isValidRole(role Role) bool {
	return slices.Contains(roleHierarchy, role)
}

// SECURE: Proper authorization checks
func updateUserRole(w http.ResponseWriter, r *http.Request) {
	// Get requesting user from auth middleware
	requester, ok := r.Context().Value("user").(User)
	if !ok {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	var req UpdateRoleRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// SECURITY: Validate the requested role is a known valid role
	if !isValidRole(req.NewRole) {
		http.Error(w, "Invalid role specified", http.StatusBadRequest)
		return
	}

	// SECURITY: Prevent self-promotion
	if requester.ID == req.UserID {
		log.Printf("SECURITY: User %d attempted self-promotion to %s", requester.ID, req.NewRole)
		http.Error(w, "Cannot modify your own role", http.StatusForbidden)
		return
	}

	// Get target user's current role
	var targetRole Role
	err := db.QueryRow("SELECT role FROM users WHERE id = $1", req.UserID).Scan(&targetRole)
	if err == sql.ErrNoRows {
		http.Error(w, "User not found", http.StatusNotFound)
		return
	} else if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	requesterLevel := getRoleLevel(requester.Role)
	targetCurrentLevel := getRoleLevel(targetRole)
	targetNewLevel := getRoleLevel(req.NewRole)

	// SECURITY: Requester must have higher privileges than both current and new role
	if requesterLevel <= targetCurrentLevel || requesterLevel <= targetNewLevel {
		log.Printf("SECURITY: User %d (role: %s) attempted unauthorized role change for user %d from %s to %s",
			requester.ID, requester.Role, req.UserID, targetRole, req.NewRole)
		http.Error(w, "Insufficient privileges", http.StatusForbidden)
		return
	}

	// Execute the update
	_, err = db.Exec("UPDATE users SET role = $1 WHERE id = $2", req.NewRole, req.UserID)
	if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// AUDIT: Log successful role change
	log.Printf("AUDIT: User %d changed user %d role from %s to %s",
		requester.ID, req.UserID, targetRole, req.NewRole)

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "role updated"})
}
```

**Key Security Controls**:
- **Authorization verification**: Requester's role level is checked before allowing any modification
- **Self-promotion prevention**: Users cannot modify their own roles
- **Role hierarchy enforcement**: Users can only assign roles below their own level
- **Input validation**: Only predefined valid roles are accepted
- **Audit logging**: All role changes and blocked attempts are logged

Multi-tenant authorization is significantly more complex because you must isolate privileges per organization. The 2024 GitLab vulnerability (CVE-2024-0402) was exactly this type of issue - users could leverage permissions from one group to affect another.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"slices"
	"time"

