	// Prepare audit event
	auditEvent := AuditLog{
		ActorID:      requesterID,
		TargetUserID: req.TargetUserID,
		OrgID:        req.OrgID,
		Action:       "role_change",
		NewValue:     string(req.NewRole),
		IPAddress:    r.RemoteAddr,
		UserAgent:    r.UserAgent(),
		Timestamp:    time.Now().UTC(),
	}

	// SECURITY: Validate requested role is known
	if !isValidRole(req.NewRole) {
		auditEvent.Success = false
		auditEvent.Reason = "invalid_role_requested"
		logAuditEvent(ctx, auditEvent)
		http.Error(w, "Invalid role specified", http.StatusBadRequest)
		return
	}

	// SECURITY: Get requester's role IN THE SPECIFIC ORGANIZATION
	requesterOrgRole, err := getUserOrgRole(ctx, requesterID, req.OrgID)
	if err == sql.ErrNoRows {
		// CRITICAL: Requester is not a member of this org
		log.Printf("SECURITY: User %d attempted role change in org %d where they have no membership",
			requesterID, req.OrgID)
		auditEvent.Success = false
		auditEvent.Reason = "requester_not_org_member"
		logAuditEvent(ctx, auditEvent)
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	} else if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// SECURITY: Verify target user is member of this org
	if !isOrgMember(ctx, req.TargetUserID, req.OrgID) {
		auditEvent.Success = false
		auditEvent.Reason = "target_not_org_member"
		logAuditEvent(ctx, auditEvent)
		http.Error(w, "Target user not found in organization", http.StatusNotFound)
		return
	}

	// Get target's current role in this org
	targetCurrentRole, err := getUserOrgRole(ctx, req.TargetUserID, req.OrgID)
	if err != nil {
		log.Printf("Database error: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}
	auditEvent.OldValue = string(targetCurrentRole)

	// SECURITY: Prevent self-promotion
	if requesterID == req.TargetUserID {
		log.Printf("SECURITY: User %d attempted self-promotion in org %d", requesterID, req.OrgID)
		auditEvent.Success = false
		auditEvent.Reason = "self_promotion_blocked"
		logAuditEvent(ctx, auditEvent)
		http.Error(w, "Cannot modify your own role", http.StatusForbidden)
		return
	}

	requesterLevel := getRoleLevel(requesterOrgRole)
	targetCurrentLevel := getRoleLevel(targetCurrentRole)
	targetNewLevel := getRoleLevel(req.NewRole)

	// SECURITY: Only owners and admins can change roles
	if requesterLevel < getRoleLevel(RoleAdmin) {
		log.Printf("SECURITY: User %d (role: %s) insufficient privileges for role changes in org %d",
			requesterID, requesterOrgRole, req.OrgID)
		auditEvent.Success = false
		auditEvent.Reason = "insufficient_base_privileges"
		logAuditEvent(ctx, auditEvent)
		http.Error(w, "Insufficient privileges", http.StatusForbidden)
		return
	}

	// SECURITY: Can only modify roles below your own level
	if requesterLevel <= targetCurrentLevel {
		log.Printf("SECURITY: User %d cannot modify user %d (same or higher role) in org %d",
			requesterID, req.TargetUserID, req.OrgID)
		auditEvent.Success = false
		auditEvent.Reason = "target_role_too_high"
		logAuditEvent(ctx, auditEvent)
		http.Error(w, "Cannot modify users with same or higher role", http.StatusForbidden)
		return
	}

	// SECURITY: Cannot assign roles equal to or higher than your own
	if targetNewLevel >= requesterLevel {
		log.Printf("SECURITY: User %d attempted to assign role %s (>= own role %s) in org %d",
			requesterID, req.NewRole, requesterOrgRole, req.OrgID)
		auditEvent.Success = false
		auditEvent.Reason = "assigned_role_too_high"
		logAuditEvent(ctx, auditEvent)
		http.Error(w, "Cannot assign roles at or above your own level", http.StatusForbidden)
		return
	}

	// SECURITY: Prevent demotion of last owner
	if targetCurrentRole == RoleOwner && req.NewRole != RoleOwner {
		ownerCount, err := countOrgOwners(ctx, req.OrgID)
		if err != nil {
			log.Printf("Database error: %v", err)
			http.Error(w, "Internal error", http.StatusInternalServerError)
			return
		}
		if ownerCount <= 1 {
			auditEvent.Success = false
			auditEvent.Reason = "cannot_remove_last_owner"
			logAuditEvent(ctx, auditEvent)
			http.Error(w, "Cannot demote the last owner", http.StatusConflict)
			return
		}
	}

	// Execute the update within a transaction
	tx, err := db.BeginTx(ctx, nil)
	if err != nil {
		log.Printf("Transaction error: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}
	defer tx.Rollback()

	_, err = tx.ExecContext(ctx,
		`UPDATE org_memberships 
		 SET role = $1, updated_at = NOW(), updated_by = $2 
		 WHERE user_id = $3 AND org_id = $4 AND deleted_at IS NULL`,
		req.NewRole, requesterID, req.TargetUserID, req.OrgID,
	)
	if err != nil {
		log.Printf("Update error: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	if err = tx.Commit(); err != nil {
		log.Printf("Commit error: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	// SUCCESS: Log audit event
	auditEvent.Success = true
	auditEvent.Reason = "success"
	logAuditEvent(ctx, auditEvent)

	log.Printf("AUDIT: User %d changed user %d role from %s to %s in org %d",
		requesterID, req.TargetUserID, targetCurrentRole, req.NewRole, req.OrgID)

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]interface{}{
		"status":     "success",
		"user_id":    req.TargetUserID,
		"org_id":     req.OrgID,
		"old_role":   targetCurrentRole,
		"new_role":   req.NewRole,
		"changed_by": requesterID,
	})
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/api/orgs/members/role", updateOrgUserRole).Methods("PUT")
	http.ListenAndServe(":8080", r)
}
```

**Defense in Depth Layers**:

1. **Organization-scoped authorization** - Always fetch and verify the requester's role within the SPECIFIC organization being modified:
```go
// NEVER use global roles for org-specific actions
requesterOrgRole, err := getUserOrgRole(ctx, requesterID, req.OrgID)
if err == sql.ErrNoRows {
    // Not a member = no access, period
    http.Error(w, "Access denied", http.StatusForbidden)
    return
}
```

2. **Hierarchical enforcement** - Multiple checks ensure vertical escalation is impossible:
```go
// Check 1: Requester must have admin+ role
if requesterLevel < getRoleLevel(RoleAdmin) { /* deny */ }

// Check 2: Cannot modify users at same or higher level
if requesterLevel <= targetCurrentLevel { /* deny */ }

// Check 3: Cannot assign roles at or above own level
if targetNewLevel >= requesterLevel { /* deny */ }
```

3. **Business logic protection** - Prevent dangerous edge cases:
```go
// Prevent orphaned organizations
if targetCurrentRole == RoleOwner && req.NewRole != RoleOwner {
    ownerCount, _ := countOrgOwners(ctx, req.OrgID)
    if ownerCount <= 1 {
        http.Error(w, "Cannot demote the last owner", http.StatusConflict)
        return
    }
}
```

**Additional Protections**:
- **Comprehensive audit logging**: Every attempt (success or failure) is logged with IP, user agent, and reason
- **Transaction safety**: Role changes are atomic to prevent partial updates
- **Context timeouts**: Prevents long-running requests from hanging
- **Soft delete support**: Queries check `deleted_at IS NULL` to respect soft-deleted memberships
- **Updated by tracking**: Records who made each change for forensic purposes
- **Rate limiting** (implement via middleware): Prevent brute-force privilege escalation attempts
